  "integration_assessment": {
    "component_interactions": [
      {
        "from": "UserService",
        "to": "PostgreSQL (users.profile_version)",
        "status": "correct",
        "issue": "Write path is clean — nullable column, no schema conflict during rollout window."
      },
      {
        "from": "ProfileService",
        "to": "PostgreSQL (users.profile_version)",
        "status": "risk",
        "issue": "ProfileService reads a column written by UserService. During the window after UserService deploy but before ProfileService deploy, data accumulates unread — acceptable. However, for OLD records never updated by UserService, profile_version remains null indefinitely, triggering perpetual full-refresh fallback until UserService happens to update those users. No backfill plan exists."
      },
      {
        "from": "Schema migration",
        "to": "PostgreSQL (profiles.version)",
        "status": "risk",
        "issue": "Migration adds profiles.version column but NEITHER service reads or writes it per the spec. Orphan column creates confusion for on-call engineers and future developers. Either the spec is incomplete or the column is dead."
      }
    ],
    "contract_compliance": "No explicit contract (schema, protobuf, OpenAPI) governs the cross-service data dependency on users.profile_version. This is an implicit integration — one service writes a column another reads — with no versioned contract. Changes to write semantics in UserService can silently break ProfileService.",
